import { DurableObject } from "cloudflare:workers";

export interface Env {
  MY_DURABLE_OBJECT: DurableObjectNamespace<MyDurableObject>;
}

/**
 * A Durable Object backed by a private, embedded SQLite database. Each named
 * instance is a single point of coordination and owns its own storage.
 */
export class MyDurableObject extends DurableObject<Env> {
  constructor(ctx: DurableObjectState, env: Env) {
    super(ctx, env);
  }

  async sayHello(): Promise<string> {
    const row = this.ctx.storage.sql
      .exec<{ greeting: string }>("SELECT 'Hello, World!' as greeting")
      .one();
    return row.greeting;
  }
}

export default {
  async fetch(request, env): Promise<Response> {
    const stub = env.MY_DURABLE_OBJECT.getByName(new URL(request.url).pathname);
    const greeting = await stub.sayHello();
    return new Response(greeting);
  },
} satisfies ExportedHandler<Env>;

