  async sayHello(): Promise<string> {
    const row = this.ctx.storage.sql
      .exec<{ value: number }>(
        `INSERT INTO counter (id, value) VALUES (1, 1)
         ON CONFLICT(id) DO UPDATE SET value = value + 1
         RETURNING value`,
      )
      .one();
    return `Hello, World! (call #${row.value})`;
  }

  /**
   * Uses the key-value Storage API (no SQL). On a SQLite-backed Durable Object
   * this data is transparently persisted in a hidden internal SQLite table,
   * which is why it shows up in Studio / the Explorer API alongside our own
   * tables.
   */
  async kvPing(): Promise<string> {
    const current = (await this.ctx.storage.get<number>("kv-counter")) ?? 0;
    const next = current + 1;
    await this.ctx.storage.put("kv-counter", next);
    return `KV pong (count #${next})`;
  }
}

export default {
  async fetch(request, env): Promise<Response> {
    const url = new URL(request.url);
    // Stable instance name via ?name= so SQL and KV calls share one object.
    const stub = env.MY_DURABLE_OBJECT.getByName(
      url.searchParams.get("name") ?? "default",
    );
    const body =
      url.pathname === "/kv" ? await stub.kvPing() : await stub.sayHello();
    return new Response(body);
  },
} satisfies ExportedHandler<Env>;

